class PredictiveCache{constructor(){this.userPatterns=new Map,this.predictions=new Map,this.maxPatterns=100,this.preloadQueue=[],this.isPreloading=!1}recordAction(t,e,s={}){this.userPatterns.has(t)||this.userPatterns.set(t,[]);const r=this.userPatterns.get(t);r.push({action:e,metadata:s,timestamp:Date.now()}),r.length>this.maxPatterns&&r.shift(),this.updatePredictions(t)}updatePredictions(t){const e=this.userPatterns.get(t)||[];if(e.length<3)return;const s={},r=e.slice(-10);for(let t=0;t<r.length-1;t++){const e=r[t].action,i=r[t+1].action;s[e]||(s[e]={}),s[e][i]=(s[e][i]||0)+1}this.predictions.set(t,s)}predictNext(t){const e=this.userPatterns.get(t)||[];if(0===e.length)return null;const s=e[e.length-1].action,r=this.predictions.get(t)||{},i=Object.entries(r[s]||{}).sort((t,e)=>e[1]-t[1]);return i.length>0?i[0][0]:null}async preloadPredicted(t,e,s){const r=this.predictNext(t);if("nextQuestion"===r&&e+1<s.length){const t=s[e+1];await this.preloadQuestion(t)}else"viewResults"===r&&await this.preloadResults(t)}async preloadQuestion(t){if(!t)return;const e=[];t.gambar&&e.push(t.gambar),t.opsi&&Array.isArray(t.opsi)&&t.opsi.forEach(t=>{t.gambar&&e.push(t.gambar)});const s=e.map(t=>new Promise(e=>{const s=new Image;s.onload=()=>e(),s.onerror=()=>e(),s.src=t}));return Promise.all(s)}async preloadResults(t){try{const e=await gasRun("getStudentResult",t);await this.cacheResults(t,e)}catch(t){console.warn("[PredictiveCache] Preload results error:",t)}}async cacheResults(t,e){try{const s=await caches.open("results-v1"),r=new Response(JSON.stringify(e),{headers:{"Content-Type":"application/json"}});await s.put(`/results/${t}`,r)}catch(t){console.warn("[PredictiveCache] Cache results error:",t)}}getMetrics(){const t=this.userPatterns.size,e=Array.from(this.userPatterns.values()).reduce((t,e)=>t+e.length,0);return{totalUsers:t,totalActions:e,avgActionsPerUser:t>0?e/t:0,predictionsCount:this.predictions.size}}clear(){this.userPatterns.clear(),this.predictions.clear()}}"undefined"!=typeof window&&(window.predictiveCache=new PredictiveCache,console.log("[PredictiveCache] ✅ Initialized"));